var resolveOfflineNavigationResponse = async (pathname = "/") => {
	for (const candidate of OFFLINE_DOC_CANDIDATES) {
		const hit = await safeCachesMatch(candidate);
		if (hit) return hit;
	}
	return createOfflineDocumentResponse(pathname);
};
var warmupOfflineNavigationCache = async (reason) => {
	try {
		const cache = await caches.open("default-cache");
		const origin = self.location.origin;
		await Promise.all(OFFLINE_WARMUP_PATHS.map(async (path) => {
			try {
				const request = new Request(new URL(path, origin).toString(), {
					method: "GET",
					credentials: "same-origin",
					cache: "no-store"
				});
				const response = await fetch(request);
				if (!response?.ok) {
					console.warn(`[SW] Warmup skipped (non-ok): ${path} status=${response?.status}`);
					return;
				}
				await cache.put(request, response.clone());
			} catch (entryError) {
				console.warn(`[SW] Warmup failed for ${path}:`, entryError);
			}
		}));
		console.log(`[SW] Offline navigation warmup completed (${reason})`);
	} catch (error) {
		console.warn(`[SW] Offline navigation warmup failed (${reason}):`, error);
	}
};
setCatchHandler(({ event }) => {
	if (event?.request?.destination === "document") {
		const pathname = (() => {
			try {
				return new URL(event?.request?.url || "").pathname || "/";
			} catch {
				return "/";
			}
		})();
		if (safeIsUserScopePath(pathname)) return handleUserOpfsGet({
			url: (() => {
				try {
					return new URL(event?.request?.url || "");
				} catch {
					return new URL(self.location.origin);
				}
			})(),
			request: event?.request,
			event
		}).catch(() => userOpfsNotFoundResponse(pathname, "GET"));
		return resolveOfflineNavigationResponse(pathname);
	}
	return Promise.resolve(Response.error());
});
self.addEventListener?.("notificationclick", (event) => {
	event?.notification?.close?.();
	event?.waitUntil?.(self.clients?.matchAll?.({
		type: "window",
		includeUncontrolled: true
	})?.then?.((clientList) => {
		for (const client of clientList) if (client.url && "focus" in client) return client.focus();
		if (self.clients?.openWindow) return self.clients?.openWindow?.("/");
	}));
});
self.addEventListener?.("install", (e) => {
	console.log("[SW] Installing new service worker...");
	const sw = self?.skipWaiting?.();
	e?.waitUntil?.(sw && typeof sw.then === "function" ? sw : Promise.resolve());
	warmupOfflineNavigationCache("install");
});
self.addEventListener?.("activate", (e) => {
	console.log("[SW] Activating service worker...");
	e?.waitUntil?.(Promise.all([self.clients?.claim?.(), self.registration?.navigationPreload?.enable?.() ?? Promise.resolve()]).then(() => notifyClients("sw-activated")).catch(() => notifyClients("sw-activated")));
	warmupOfflineNavigationCache("activate");
});
self.addEventListener?.("message", (e) => {
	const { type } = e.data || {};
	switch (type) {
		case "SKIP_WAITING":
			console.log("[SW] Received skip waiting command");
			self.skipWaiting?.();
			break;
		case "CHECK_FOR_UPDATES":
			console.log("[SW] Checking for updates...");
			e.waitUntil?.(checkForUpdates());
			break;
		case "GET_CACHE_STATUS":
			e.waitUntil?.(sendCacheStatus(e.source));
			break;
		default: console.log("[SW] Unknown message type:", type);
	}
});
async function notifyClients(type, data) {
	(await self.clients?.matchAll?.() || []).forEach((client) => {
		client.postMessage({
			type,
			data
		});
	});
}
async function checkForUpdates() {
	try {
		const registration = self.registration;
		if (registration) {
			await registration.update();
			console.log("[SW] Update check completed");
		}
	} catch (error) {
		console.error("[SW] Update check failed:", error);
	}
}
async function sendCacheStatus(client) {
	try {
		const cacheNames = await caches.keys();
		const cacheStatus = {};
		for (const cacheName of cacheNames) {
			const keys = await (await caches.open(cacheName)).keys();
			cacheStatus[cacheName] = {
				name: cacheName,
				size: keys.length,
				urls: keys.map((request) => request.url)
			};
		}
		client.postMessage({
			type: "cache-status",
			data: cacheStatus
		});
	} catch (error) {
		console.error("[SW] Failed to get cache status:", error);
	}
}
registerRoute(({ url, request }) => isShareTargetUrl(url?.pathname) && request?.method === "GET", async ({ event }) => {
	const navEvent = event;
	const preloadPromise = navEvent?.preloadResponse ? Promise.resolve(navEvent.preloadResponse).catch(() => void 0) : null;
	if (preloadPromise) {
		navEvent.waitUntil(preloadPromise.then(() => void 0));
		await preloadPromise;
	}
	console.log("[ShareTarget] GET request received - redirecting to app");
	return new Response(null, {
		status: 302,
		headers: { Location: "/workcenter?shared=1" }
	});
}, "GET");
self.addEventListener?.("fetch", (event) => {
	const request = event?.request ?? event?.event?.request ?? event;
	if (!request?.url) return;
	const requestUrl = new URL(request.url);
	if (safeIsUserScopePath(requestUrl.pathname)) {
		const method = String(request.method || "GET").toUpperCase();
		if (method === "GET") {
			event?.respondWith?.(handleUserOpfsGet({
				url: requestUrl,
				request,
				event
			}));
			return;
		}
		if (method === "POST") {
			event?.respondWith?.(handleUserOpfsWrite({
				url: requestUrl,
				request,
				event
			}, "POST"));
			return;
		}
		if (method === "PUT" || method === "PATCH") {
			event?.respondWith?.(handleUserOpfsWrite({
				url: requestUrl,
				request,
				event
			}, "PUT"));
			return;
		}
		if (method === "DELETE") {
			event?.respondWith?.(handleUserOpfsDelete({
				url: requestUrl,
				request,
				event
			}));
			return;
		}
		if (method === "OPTIONS") {
			event?.respondWith?.(new Response(null, {
				status: 204,
				headers: {
					"Cache-Control": "no-store",
					"Pragma": "no-cache",
					"Expires": "0",
					"Access-Control-Allow-Methods": "GET,POST,PUT,PATCH,DELETE,OPTIONS",
					"Access-Control-Allow-Headers": "Content-Type, X-File-Name, X-Filename",
					"X-Source": "opfs-user"
				}
			}));
			return;
		}
		event?.respondWith?.(jsonUserOpfsResponse({
			ok: false,
			error: "OPFS_METHOD_NOT_ALLOWED",
			status: 405,
			method,
			path: requestUrl.pathname
		}, 405));
		return;
	}
	if (isShareTargetUrl(requestUrl.pathname) && request?.method === "POST") {
		console.log("[ShareTarget] Manual fetch handler triggered");
		event?.respondWith?.(handleShareTargetRequest(request));
	}
});
async function handleShareTargetRequest(event) {
	const request = event?.request ?? event?.event?.request ?? event;
	const contentType = (request?.headers ?? event?.event?.request?.headers ?? event?.headers ?? {})?.get?.("content-type") ?? "";
	console.log("[ShareTarget] Manual handler called for:", request.url);
	console.log("[ShareTarget] Service worker controlling clients:", !!self.clients);
	try {
		const fd = await request?.formData?.().catch?.((error) => {
			console.error("[ShareTarget] Failed to parse FormData:", error);
			return null;
		});
		if (!fd) {
			console.warn("[ShareTarget] No FormData received");
			return new Response(null, {
				status: 302,
				headers: { Location: "/" }
			});
		}
		console.log("[ShareTarget] FormData received, content-type:", contentType);
		console.log("[ShareTarget] FormData keys:", Array.from(fd?.keys?.() || []));
		const shareData = {
			title: fd?.get?.("title") || "",
			text: fd?.get?.("text") || "",
			url: fd?.get?.("url") || "",
			files: fd?.getAll?.("files") || [],
			timestamp: Date.now()
		};
		console.log("[ShareTarget] Processed data:", {
			title: shareData?.title,
			text: shareData?.text?.substring(0, 50),
			url: shareData?.url,
			filesCount: shareData?.files?.length || 0
		});
		let primaryContentType = "text";
		if (shareData.files?.length > 0) primaryContentType = "files";
		else if (shareData.url) primaryContentType = "url";
		return await processContentWithAssociation(primaryContentType, "share-target", shareData, event);
	} catch (err) {
		console.warn("[ShareTarget] Manual handler error:", err);
		return new Response(null, {
			status: 302,
			headers: { Location: "/" }
		});
	}
}
registerRoute(({ url }) => {
	const matches = url?.pathname === "/clipboard/pending";
	if (matches) console.log("[SW] Clipboard route matched for:", url?.pathname);
	return matches;
}, async ({ url }) => {
	try {
		console.log("[SW] Handling request for pending clipboard operations:", url?.pathname);
		const operations = await getStoredClipboardOperations();
		console.log("[SW] Returning", operations.length, "clipboard operations");
		return new Response(JSON.stringify({ operations }), { headers: { "Content-Type": "application/json" } });
	} catch (error) {
		console.error("[SW] Error in clipboard pending route:", error);
		return new Response(JSON.stringify({ error: "Internal server error" }), {
			status: 500,
			headers: { "Content-Type": "application/json" }
		});
	}
}, "GET");
registerRoute(({ url }) => url?.pathname === "/sw-content/available", async () => {
	console.log("[SW] Received request for available cached content");
	const cacheKeys = await getStoredCacheKeys();
	return new Response(JSON.stringify({ cacheKeys }), { headers: { "Content-Type": "application/json" } });
}, "GET");
registerRoute(({ url }) => url?.pathname?.startsWith("/sw-content/"), async ({ url }) => {
	const cacheKey = url.pathname.replace("/sw-content/", "");
	console.log("[SW] Received request for cached content:", cacheKey);
	if (!cacheKey) return new Response(JSON.stringify({ error: "Missing cache key" }), {
		status: 400,
		headers: { "Content-Type": "application/json" }
	});
	try {
		const cache = await self.caches?.open?.(SW_CONTENT_CACHE_NAME);
		if (cache) {
			const cacheRequest = toSWContentCacheRequest(cacheKey);
			const response = await safeCacheMatch(cache, cacheRequest);
			if (response) {
				await cache.delete(cacheRequest);
				return response;
			}
		}
	} catch (error) {
		console.warn("[SW] Failed to retrieve cached content:", error);
	}
	return new Response(JSON.stringify({ error: "Content not found" }), {
		status: 404,
		headers: { "Content-Type": "application/json" }
	});
}, "GET");
registerRoute(({ url }) => url?.pathname === "/share-target-files", async ({ url }) => {
	const cacheKey = url.searchParams.get("cacheKey") || "latest";
	console.log("[SW] Received request for share target files, cacheKey:", cacheKey);
	try {
		const cache = await self.caches?.open?.(SHARE_CACHE_NAME);
		if (cache) {
			const manifestResponse = await safeCacheMatch(cache, SHARE_FILES_MANIFEST_KEY);
			if (manifestResponse) {
				const manifest = await manifestResponse.json();
				return new Response(JSON.stringify(manifest), { headers: { "Content-Type": "application/json" } });
			}
		}
	} catch (error) {
		console.warn("[SW] Failed to retrieve share target file manifest:", error);
	}
	return new Response(JSON.stringify({ files: [] }), { headers: { "Content-Type": "application/json" } });
}, "GET");
registerRoute(({ url }) => url?.pathname?.startsWith(SHARE_FILE_PREFIX), async ({ url }) => {
	const fileKey = url.pathname.replace(SHARE_FILE_PREFIX, "");
	console.log("[SW] Received request for share target file:", fileKey);
	if (!fileKey) return new Response(JSON.stringify({ error: "Missing file key" }), {
		status: 400,
		headers: { "Content-Type": "application/json" }
	});
	try {
		const cache = await self.caches?.open?.(SHARE_CACHE_NAME);
		if (cache) {
			const response = await safeCacheMatch(cache, SHARE_FILE_PREFIX + fileKey);
			if (response) return response;
		}
	} catch (error) {
		console.warn("[SW] Failed to retrieve share target file:", error);
	}
	return new Response(JSON.stringify({ error: "File not found" }), {
		status: 404,
		headers: { "Content-Type": "application/json" }
	});
}, "GET");
self.addEventListener?.("launchqueue", async (event) => {
	console.log("[LaunchQueue] Launch queue event received");
	try {
		const launchQueue = event?.launchQueue;
		if (!launchQueue) {
			console.warn("[LaunchQueue] No launch queue available");
			return;
		}
		console.log("[LaunchQueue] Launch queue payload summary:", summarizeForLog({
			fileCount: launchQueue?.files?.length,
			hasFilesIterator: typeof launchQueue?.files?.[Symbol.asyncIterator] === "function"
		}));
		const files = [];
		for await (const fileHandle of launchQueue.files) try {
			console.log("[LaunchQueue] Processing file:", fileHandle.name);
			const file = await fileHandle.getFile();
			console.log("[LaunchQueue] File loaded from handle:", summarizeForLog({
				name: file?.name,
				type: file?.type,
				size: file?.size
			}));
			files.push(file);
		} catch (error) {
			console.error("[LaunchQueue] Failed to process file:", error);
		}
		if (files.length <= 0) return;
		const categorized = categorizeFiles(files);
		const shareData = {
			title: "",
			text: "",
			url: "",
			files,
			imageFiles: categorized.imageFiles,
			textFiles: categorized.textFiles,
			otherFiles: categorized.otherFiles,
			timestamp: Date.now()
		};
		await cacheShareData(shareData);
		notifyShareReceived?.({
			timestamp: shareData.timestamp,
			fileCount: shareData.files.length,
			imageCount: shareData.imageFiles.length,
			source: "launch-queue",
			route: "launch-queue"
		});
		sendToast(`Received ${shareData.files.length} launched file(s)`, "info");
		const targetUrl = "/share-target?shared=1";
		const clientsList = await self.clients?.matchAll?.({
			type: "window",
			includeUncontrolled: true
		}) || [];
		if (clientsList.length > 0) await clientsList[0].focus?.();
		else await self.clients?.openWindow?.(targetUrl);
	} catch (error) {
		console.error("[LaunchQueue] Failed to handle launch queue:", error);
	}
});
self.addEventListener?.("push", async (event) => {
	console.log("[Push] Push message received");
	try {
		const data = event?.data?.json?.() || {};
		await processContentWithAssociation("text", "push-message", {
			text: data.message || data.body || "",
			title: data.title || "",
			timestamp: Date.now(),
			source: "push"
		}, event);
	} catch (error) {
		console.error("[Push] Failed to handle push message:", error);
	}
});
self.addEventListener?.("sync", async (event) => {
	console.log("[BackgroundSync] Background sync event:", event.tag);
	if (event.tag === "content-processing") try {
		const cacheKeys = await getStoredCacheKeys();
		const processingKeys = cacheKeys.filter((k) => k.context === "background-sync");
		for (const cacheKey of processingKeys) try {
			const cache = await self.caches?.open?.(SW_CONTENT_CACHE_NAME);
			if (cache) {
				const cacheRequest = toSWContentCacheRequest(cacheKey.key);
				const response = await safeCacheMatch(cache, cacheRequest);
				if (response) {
					await processContentWithAssociation("any", "background-sync", await response.json(), event);
					await cache.delete(cacheRequest);
				}
			}
		} catch (error) {
			console.error("[BackgroundSync] Failed to process cached content:", error);
		}
		await storeCacheKeys(cacheKeys.filter((k) => k.context !== "background-sync"));
	} catch (error) {
		console.error("[BackgroundSync] Failed to handle background sync:", error);
	}
});
registerRoute(({ url }) => url?.pathname === "/clipboard/clear", async () => {
	console.log("[SW] Clearing clipboard operations queue");
	await clearStoredClipboardOperations();
	return new Response(JSON.stringify({ success: true }), { headers: { "Content-Type": "application/json" } });
}, "POST");
registerRoute(({ url }) => url?.pathname.startsWith("/clipboard/remove/"), async ({ url }) => {
	const operationId = url?.pathname.split("/clipboard/remove/")[1];
	if (!operationId) return new Response(JSON.stringify({ error: "Missing operation ID" }), {
		status: 400,
		headers: { "Content-Type": "application/json" }
	});
	console.log("[SW] Removing clipboard operation:", operationId);
	await removeClipboardOperation(operationId);
	return new Response(JSON.stringify({ success: true }), { headers: { "Content-Type": "application/json" } });
}, "DELETE");
registerRoute(({ url }) => {
	const pathname = url?.pathname;
	return pathname && !safeIsUserScopePath(pathname) && (pathname.endsWith(".js") || pathname.endsWith(".css") || pathname.endsWith(".svg") || pathname.endsWith(".png") || pathname === "/sw.js");
}, handleAssetRequest);
registerRoute(({ url, request }) => request.mode === "navigate" && !safeIsUserScopePath(url?.pathname || ""), async ({ event, request }) => {
	try {
		const preloadPromise = event?.preloadResponse ? Promise.resolve(event.preloadResponse).catch(() => void 0) : null;
		if (preloadPromise) {
			event.waitUntil(preloadPromise.then(() => void 0));
			const preloadResponse = await preloadPromise;
			if (preloadResponse) return preloadResponse;
		}
		return await fetch(request);
	} catch (error) {
		console.warn("[SW] Navigation fetch failed:", error);
		const pathname = (() => {
			try {
				return new URL(request?.url || "").pathname || "/";
			} catch {
				return "/";
			}
		})();
		if (safeIsUserScopePath(pathname)) return await handleUserOpfsGet({
			url: (() => {
				try {
					return new URL(request?.url || "");
				} catch {
					return new URL(self.location.origin);
				}
			})(),
			request,
			event
		}).catch(() => userOpfsNotFoundResponse(pathname, "GET"));
		return await resolveOfflineNavigationResponse(pathname);
	}
});
